\title{From Patient to Caregiver: \\
A Community Engagement Study of AI-Powered Oral Health Screening for Older Adults}
\author{Puru Soni\textsuperscript{1},
    Kritarth Dandapat\textsuperscript{1},
    Alexander Gherardi\textsuperscript{1},
    \\Wei Bo\textsuperscript{1*},
